import{_ as a,o as l,c as s,ai as i}from"./chunks/framework.CsYGeNYI.js";const m=JSON.parse('{"title":"Skills","description":"","frontmatter":{"summary":"macOS Skills settings UI and gateway-backed status","read_when":["Updating the macOS Skills settings UI","Changing skills gating or install behavior"],"title":"Skills"},"headers":[],"relativePath":"platforms/mac/skills.md","filePath":"platforms/mac/skills.md","lastUpdated":1771906665000}'),t={name:"platforms/mac/skills.md"};function o(n,e,d,r,c,h){return l(),s("div",null,[...e[0]||(e[0]=[i('<h1 id="skills-macos" tabindex="-1"><a class="header-anchor" href="#skills-macos">#</a> Skills (macOS)</h1><p>The macOS app surfaces OpenSoul skills via the gateway; it does not parse skills locally.</p><h2 id="data-source" tabindex="-1"><a class="header-anchor" href="#data-source">#</a> Data source</h2><ul><li><code>skills.status</code> (gateway) returns all skills plus eligibility and missing requirements (including allowlist blocks for bundled skills).</li><li>Requirements are derived from <code>metadata.opensoul.requires</code> in each <code>SKILL.md</code>.</li></ul><h2 id="install-actions" tabindex="-1"><a class="header-anchor" href="#install-actions">#</a> Install actions</h2><ul><li><code>metadata.opensoul.install</code> defines install options (brew/node/go/uv).</li><li>The app calls <code>skills.install</code> to run installers on the gateway host.</li><li>The gateway surfaces only one preferred installer when multiple are provided (brew when available, otherwise node manager from <code>skills.install</code>, default npm).</li></ul><h2 id="env-api-keys" tabindex="-1"><a class="header-anchor" href="#env-api-keys">#</a> Env/API keys</h2><ul><li>The app stores keys in <code>~/.opensoul/opensoul.json</code> under <code>skills.entries.&lt;skillKey&gt;</code>.</li><li><code>skills.update</code> patches <code>enabled</code>, <code>apiKey</code>, and <code>env</code>.</li></ul><h2 id="remote-mode" tabindex="-1"><a class="header-anchor" href="#remote-mode">#</a> Remote mode</h2><ul><li>Install + config updates happen on the gateway host (not the local Mac).</li></ul>',10)])])}const u=a(t,[["render",o]]);export{m as __pageData,u as default};
